#include <vector>
#include <numeric>
#include <cmath>
#include <iostream>

using namespace std;

/**
 * @brief Checks if a subarray is "good".
 * 
 * A subarray is "good" if the bitwise OR of all its elements equals at least one element present in the subarray.
 * 
 * @param subarray The subarray to check.
 * @return true if the subarray is good, false otherwise.
 */
bool is_good(const vector<long long>& subarray) {
    if (subarray.empty()) return false;

    // 1. Calculate the bitwise OR of all elements
    long long subarray_or = 0;
    for (long long x : subarray) {
        subarray_or |= x;
    }

    // 2. Check if this OR value exists in the subarray
    for (long long x : subarray) {
        if (subarray_or == x) {
            return true;
        }
    }

    return false;
}

/**
 * @brief Solves the problem of counting good subarrays.
 * 
 * @param nums The input array.
 * @return The total number of good subarrays.
 */
long long solve(const vector<long long>& nums) {
    int n = nums.size();
    long long good_subarray_count = 0;

    // Iterate over all possible starting indices i
    for (int i = 0; i < n; ++i) {
        long long current_or = 0;
        // Iterate over all possible ending indices j (j >= i)
        for (int j = i; j < n; ++j) {
            // Extend the subarray from [i, j-1] to [i, j]
            current_or |= nums[j];

            // The subarray is nums[i...j]

            // We need to check if 'current_or' exists in nums[i...j].
            // Instead of reconstructing the subarray and calling is_good (which is O(j-i+1)),
            // we can maintain a set or check directly if current_or is equal to any of nums[i...j].

            // Since current_or is the OR of nums[i...j], if current_or == nums[k] for some k in [i, j],
            // then nums[k] must be one of the elements in the subarray.

            // Optimization: The condition is: current_or == nums[k] for some i <= k <= j.
            // We only need to check if current_or is present in {nums[i], nums[i+1], ..., nums[j]}.

            bool found = false;
            for (int k = i; k <= j; ++k) {
                if (current_or == nums[k]) {
                    found = true;
                    break;
                }
            }

            if (found) {
                good_subarray_count++;
            }
        }
    }

    return good_subarray_count;
}
