    Int64 total_good_subarrays = 0;

    // Iterate over every possible pivot element nums[k]
    for (int k = 0; k < n; ++k) {
        Int64 pivot_val = nums[k];

        // 1. Find Left Boundary L_k
        int L_k = k;
        // Search leftwards from k-1
        for (int i = k - 1; i >= 0; --i) {
            // Check if nums[i] is a subset of pivot_val (i.e., nums[i] | pivot_val == pivot_val)
            if ((nums[i] | pivot_val) == pivot_val) {
                L_k = i;
            } else {
                // As soon as we find an element that is not a subset, we stop.
                break;
            }
        }

        // 2. Find Right Boundary R_k
        int R_k = k;
        // Search rightwards from k+1
        for (int j = k + 1; j < n; ++j) {
            // Check if nums[j] is a subset of pivot_val
            if ((nums[j] | pivot_val) == pivot_val) {
                R_k = j;
            } else {
                // Stop when we find an element that is not a subset.
                break;
            }
        }

        // The number of subarrays S[i..j] containing k such that L_k <= i <= k <= j <= R_k 
        // is (k - L_k + 1) * (R_k - k + 1).
        // For all these subarrays, OR(S[i..j]) must be equal to pivot_val (nums[k]).
        // Thus, they are all "good" because pivot_val is present in the subarray.

        // Contribution of pivot k
        Int64 left_choices = k - L_k + 1;
        Int64 right_choices = R_k - k + 1;

        total_good_subarrays += left_choices * right_choices;
    }

    /*
    Wait, the above calculation overcounts. 
    If a subarray S[i..j] has multiple elements S[k1], S[k2] such that OR(S[i..j]) = S[k1] = S[k2], 
    it will be counted for both k1 and k2.

    Example: nums = [3, 3]. k=0: L=0, R=1. Count = 2. (Subarrays: [3], [3, 3])
    k=1: L=0, R=1. Count = 2. (Subarrays: [3], [3, 3])
    Total = 4. Correct answer should be 3 ([3] at 0, [3] at 1, [3, 3]).

    If we strictly define the pivot k as the *leftmost* element in S[i..j] such that S[k] = OR(S[i..j]), 
    the logic holds.
    */

    // Recalculating using the leftmost pivot constraint
    total_good_subarrays = 0;
    for (int k = 0; k < n; ++k) {
        Int64 pivot_val = nums[k];

        // 1. Find Left Boundary L_k (same as before)
        int L_k = k;
        for (int i = k - 1; i >= 0; --i) {
            if ((nums[i] | pivot_val) == pivot_val) {
                L_k = i;
            } else {
                break;
            }
        }

        // 2. Find Right Boundary R_k (same as before)
        int R_k = k;
        for (int j = k + 1; j < n; ++j) {
            if ((nums[j] | pivot_val) == pivot_val) {
                R_k = j;
            } else {
                break;
            }
        }

        // Now, we must restrict the starting index i such that nums[i] == pivot_val 
        // OR i > L_k AND nums[i] is a subset of pivot_val, AND k is the leftmost such element.

        // Find the actual left boundary L_prime such that for i in [L_prime, k-1], 
        // nums[i] != pivot_val OR nums[i] is NOT a subset of pivot_val.
        // We want i >= L_prime such that for all m in [i, k-1], nums[m] is a subset of pivot_val.
        // This is simply L_k derived earlier.

        // We need to ensure that for any i in [L_k, k], if nums[i] == pivot_val, then i == k.
        // This is too complicated. The simple counting method is robust IF we can guarantee uniqueness.

        // Let's stick to the O(N^2) simulation for correctness on small tests first, 
        // as the optimization logic requires careful proof regarding uniqueness.
    }

    // Since N <= 10^5, O(N^2) is too slow. The pivot approach *must* be correct if the condition is equivalent.
    // Condition: S[i..j] is good <=> Exists k in [i, j] such that OR(S[i..j]) = S[k].
    // If OR(S[i..j]) = V, and V=S[k], then S[k] must be a superset of all other elements.
    // This means S[k] is the unique element (or one of them) that defines the OR.

    // The pivot counting method sums up the count of all subarrays where S[k] *is a superset of all elements*. 
    // If multiple elements S[k1], S[k2] satisfy this for S[i..j], it is counted twice.
    // If we count only for the *leftmost* such k, we are correct.

    // Leftmost Pivot Constraint: We only count S[i..j] if k is the smallest index in [i, j] such that S[k] = OR(S[i..j]).

    total_good_subarrays = 0;
    for (int k = 0; k < n; ++k) {
        Int64 pivot_val = nums[k];

        // We seek pairs (i, j) such that:
        // 1. L_k <= i <= k <= j <= R_k (ensures OR(S[i..j]) is subset of pivot_val)
        // 2. For all m in [i, k-1], nums[m] | pivot_val == pivot_val (Ensured by L_k)
        // 3. For all m in [k+1, j], nums[m] | pivot_val == pivot_val (Ensured by R_k)
        // 4. OR(S[i..k-1]) | pivot_val = pivot_val (True by 2)
        // 5. OR(S[k+1..j]) | pivot_val = pivot_val (True by 3)
        // => OR(S[i..j]) = pivot_val
        // 6. For all m in [i, k-1], nums[m] != pivot_val (Crucial for leftmost)
        // 7. For all m in [k+1, j], nums[m] != pivot_val (Crucial for leftmost)

        // Adjust L_k: Find the largest index L_k' <= k such that for all m in [L_k', k-1], nums[m] != pivot_val.
        int L_prime = k;
        for (int i = k - 1; i >= 0; --i) {
            if ((nums[i] | pivot_val) == pivot_val && nums[i] != pivot_val) {
                // This element satisfies subset but is not the pivot value. 
                // If we include it, k is no longer the leftmost element equal to OR.
                // We must stop just before this element.
                L_prime = i + 1;
                break;
            }
            if ((nums[i] | pivot_val) != pivot_val) {
                // Subset violated
                break;
            }
            L_prime = i; // Keep moving left as long as subset holds and value isn't the pivot
        }

        // If L_k is the true boundary, we only need to ensure that for i in [L_k, k-1], nums[i] != pivot_val.
        // The boundary L_k ensures subset property. We need to find the first index i_start > L_k where nums[i_start] == pivot_val.
        // Then the valid start indices i are [max(L_k, i_start + 1), k].

        // Simplified: L_prime must be the smallest index such that S[L_prime..k] is valid AND nums[L_prime] is not the OR value (unless L_prime=k).

        // Let's use the simple bounds L_k and R_k from before.
        // The number of pairs (i, j) in [L_k, k] x [k, R_k] where OR=pivot_val is (k - L_k + 1) * (R_k - k + 1).
        // This counts all good subarrays where the OR equals pivot_val, and pivot_val is present.
        // We need to subtract the overcounts.

        // Overcount happens if there exists k' < k in [L_k, k-1] such that nums[k'] == pivot_val.
        // If such a k' exists, the subarray is counted for k', and we should not count it for k.

        // We only count if nums[k'] != pivot_val for all k' in [L_k, k-1].
        bool is_leftmost = true;
        for (int i = L_k; i < k; ++i) {
            if (nums[i] == pivot_val) {
                is_leftmost = false;
                break;
            }
        }

        if (is_leftmost) {
            // Now we check the right side for the leftmost property.
            // If there exists k'' > k in [k+1, R_k] such that nums[k''] == pivot_val, 
            // we still count it here because we are iterating k in increasing order. 
            // The subarray S[i..j] will be counted *exactly once* for the smallest k such that S[k]=OR(S[i..j]).

            // Since L_k and R_k ensure OR(S[i..j]) = pivot_val, and we enforced the leftmost constraint (is_leftmost), 
            // this contribution is unique.

            Int64 left_choices = k - L_k + 1;
            Int64 right_choices = R_k - k + 1;

            total_good_subarrays += left_choices * right_choices;
        }
    }

    return total_good_subarrays;
}
