                break;
            }
        }

        if (is_leftmost) {
            // Now we check the right side for the leftmost property.
            // If there exists k'' > k in [k+1, R_k] such that nums[k''] == pivot_val, 
            // we still count it here because we are iterating k in increasing order. 
            // The subarray S[i..j] will be counted *exactly once* for the smallest k such that S[k]=OR(S[i..j]).

            // Since L_k and R_k ensure OR(S[i..j]) = pivot_val, and we enforced the leftmost constraint (is_leftmost), 
            // this contribution is unique.

            Int64 left_choices = k - L_k + 1;
            Int64 right_choices = R_k - k + 1;

            total_good_subarrays += left_choices * right_choices;
        }
    }

    return total_good_subarrays;
