typedef long long int64;

int64 solve(vector<int64> nums) {
    int n = nums.size();
    int64 total_count = 0;

    // 1. Preprocessing: Store positions for fast existence check
    vector<vector<int>> positions(1000000001, vector<int>()); // Max value is 10^9, this is too large for array indexing.
    // Since we only care about values present in nums, use a map.
    map<int64, vector<int>> value_positions;
    for (int i = 0; i < n; ++i) {
        value_positions[nums[i]].push_back(i);
    }

    // current_ors stores {OR_value, leftmost_start_index} for subsegments ending at j-1.
    // We use a map to automatically handle merging identical OR values, keeping the minimum start index.
    // Map: OR_value -> leftmost_start_index
    map<int64, int> current_ors_map;

    for (int j = 0; j < n; ++j) {
        // 2. Calculate next_ors_map (for segments ending at j)
        map<int64, int> next_ors_map;

        // Case 1: Segment [j..j]
        int64 val_j = nums[j];
        next_ors_map[val_j] = j;

        // Case 2: Extend segments ending at j-1
        for (const auto& pair : current_ors_map) {
            int64 prev_val = pair.first;
            int start_i = pair.second;

            int64 new_val = prev_val | val_j;

            // Merge: if new_val already exists, keep the minimum start index
            if (next_ors_map.find(new_val) == next_ors_map.end() || start_i < next_ors_map[new_val]) {
                next_ors_map[new_val] = start_i;
            }
        }

        // 3. Convert map to sorted list L_j for range processing
        // L_j: vector of {OR_value, start_index} sorted by start_index ascending.
        vector<pair<int64, int>> L_j;
        for (const auto& pair : next_ors_map) {
            // pair.first is OR_value, pair.second is leftmost_start_index
            L_j.push_back({pair.first, pair.second});
        }

        // Sort by start_index ascending (r_k)
        sort(L_j.begin(), L_j.end(), [](const pair<int64, int>& a, const pair<int64, int>& b) {
            return a.second < b.second;
        });

        // 4. Range summation and counting
        // L_j = {(v_1, r_1), ..., (v_m, r_m)} where r_1 < r_2 < ... < r_m = j
        int m = L_j.size();

        // Use r_{m+1} = -1 for the last segment
        int r_next = -1; 

        // Iterate backwards from k=m down to 1
        for (int k = m - 1; k >= 0; --k) {
            int64 v_k = L_j[k].first;
            int r_k = L_j[k].second;

            // The range of starting indices i where OR_sum(i, j) = v_k is [r_{k+1} + 1, r_k].
            // Since L_j is sorted by r ascending, we iterate backwards, so r_{k+1} is the next index in the backward iteration.
            // If k < m-1, r_{k+1} is L_j[k+1].second. If k = m-1, r_{k+1} is the conceptual -1.

            // In our backward iteration (k=m-1 down to 0):
            // r_k = L_j[k].second
            // r_{k+1} = r_next (which holds the start index of the segment immediately to the right of the current one)

            int L = r_next + 1; // Start of the current range
            int R = r_k;       // End of the current range

            // Segment length: R - L + 1
            int64 segment_len = R - L + 1;

            // Check: Does value v_k exist in the range [L, R]?
            if (value_positions.count(v_k)) {
                const auto& positions_v = value_positions.at(v_k);

                // Find the first position >= L
                auto it = lower_bound(positions_v.begin(), positions_v.end(), L);

                // If such a position exists AND it is <= R, then the condition is met.
                if (it != positions_v.end() && *it <= R) {
                    total_count += segment_len;
                }
            }

            // Update r_next for the next iteration (k-1)
            r_next = r_k;
        }

        // Update for the next outer iteration (j -> j+1)
        current_ors_map = next_ors_map;
    }

    return total_count;
}
