using namespace std;

/**
 * @brief 解决好子数组计数问题。
 * 
 * 一个子数组的好条件是：子数组所有元素的按位或等于该子数组中至少出现一次的元素。
 * 
 * 核心观察：
 * 设子数组为 nums[i..j]，其按位或为 OR_sum。
 * 好子数组的条件是：OR_sum == nums[k] 对于某个 k in [i, j]。
 * 
 * 1. 对于长度为 1 的子数组 [nums[i]]，OR_sum = nums[i]，条件恒成立，所以总共有 N 个这样的好子数组。
 * 
 * 2. 对于长度 >= 2 的子数组 nums[i..j]，如果它是一个好子数组，则 OR_sum 必须等于某个元素 nums[k] (i <= k <= j)。
 *    因为 OR_sum 包含了所有元素的位，所以 OR_sum >= nums[k] 对于所有 k。
 *    如果 OR_sum = nums[k]，这意味着所有其他元素 nums[l] (l != k) 的位都必须被 nums[k] 包含 (即 nums[l] | nums[k] = nums[k])。
 * 
 * 我们可以固定右端点 j，然后计算有多少个左端点 i <= j 使得 nums[i..j] 是好子数组。
 * 
 * 考虑固定 j。我们寻找 i <= j 使得 OR_sum(i, j) = nums[k] for some k in [i, j].
 * 
 * 由于 OR_sum(i, j) 是单调不减的（随着 i 减小，OR_sum 不减），并且 OR_sum(i, j) 只能是有限个值。
 * 
 * 我们可以维护从 j 往前推 i 的过程中，所有不同的 OR_sum 值以及它们对应的起始点。
 * 
 * 维护一个 map 或 list 来存储所有以 j 结尾的子数组的 OR 值和它们对应的最小起始点。
 * 
 * 设 current_ors 是一个 map<int64, int>，存储 {OR_value: start_index}
 * 
 * 当从 j-1 转移到 j 时，新的 OR_values 集合由以下部分构成：
 * 1. {nums[j]} (对应 i=j)
 * 2. {old_OR_value | nums[j]} (对于所有在 j-1 结尾的子数组)
 * 
 * 这是一个经典的“动态维护前缀/子数组 OR/AND/XOR”的优化方法。
 * 在每个位置 j，我们只关心有限个不同的 OR_sum 值。
 * 
 * 设 S_j 是所有以 j 结尾的子数组的 {OR_value: start_index} 的集合。
 * S_j = { (nums[j], j) } U { (v | nums[j], i) | (v, i) in S_{j-1} }
 * 
 * 复杂度分析：
 * 不同的 OR_sum 值最多有 log(MAX_VAL) 个，因为每次 OR 操作至少增加一个位（如果值增加），或者值不变。
 * 对于 30 位整数，最多有 30 个不同的值。
 * 
 * 算法流程：
 * 1. total_count = 0
 * 2. current_ors: vector<pair<int64, int>>，存储 {OR_value, start_index}
 * 3. for j = 0 to N-1:
 *    a. next_ors = []
 *    b. Add {nums[j], j} to next_ors.
 *    c. For each {val, start_i} in current_ors:
 *       new_val = val | nums[j]
 *       new_start_i = start_i
 *       Add {new_val, new_start_i} to next_ors.
 *    d. Sort and unique next_ors based on OR_value to get S_j.
 *    e. For each {val, start_i} in S_j:
 *       // 对应的子数组是 nums[start_i .. j]
 *       // 找到所有 i in [start_i, j] 使得 OR_sum(i, j) = val
 *       // 满足 OR_sum(i, j) = val 的所有 i 形成一个连续区间 [i_min, i_max] (其中 i_min = start_i)
 *       
 *       // 实际上，如果 S_j 存储的是 {OR_value: leftmost_start_index}，那么对于某个 val，
 *       // 所有 i in [leftmost_start_index, j] 使得 OR_sum(i, j) = val 吗？不是。
 * 
 *       // 让我们重新审视 S_j 的含义：S_j 存储的是所有不同的 OR_sum 值，以及每个值第一次出现时的最左侧起始索引。
 *       // 假设 S_j = { (v1, i1), (v2, i2), ... } 且 v1 < v2 < ... (或按 i 排序)
 *       // 对于 v_k，它对应于所有 i >= i_k 且 i <= j 的子数组中，OR_sum(i, j) = v_k 的集合。
 *       // 事实上，S_j 的每个元素 (val, start_i) 代表了：对于所有 i 在 [start_i, j] 中，如果 i 满足 OR_sum(i, j) = val，则 i >= start_i。
 *       // 更精确地：(val, start_i) 表示存在一个子数组 nums[start_i..j] 的 OR 为 val，并且这是以 j 结尾的，且最左侧的起始点是 start_i。
 * 
 *       // 关键点：在 S_j 中，如果 val_k < val_{k+1}，那么对应的起始点 i_k >= i_{k+1}。
 *       // 并且，对于所有 i in [i_{k+1}, i_k - 1]，OR_sum(i, j) = val_k。
 *       
 *       // 设 S_j 的元素为 (val_1, i_1), (val_2, i_2), ..., (val_m, i_m)，排序使得 i_1 > i_2 > ... > i_m = j。
 *       // (或者更常见的，按 i 排序，i_1 < i_2 < ... < i_m = j)
 * 
 *       // 采用按起始点排序的方式（左到右，i_1 < i_2 < ... < i_m = j）：
 *       // - 对于 i in [0, i_1 - 1]，OR_sum(i, j) 是某个值 v_0。
 *       // - 对于 i in [i_k, i_{k+1} - 1]，OR_sum(i, j) = val_k。
 *       // - 对于 i in [i_m, j]，OR_sum(i, j) = val_m (通常是 nums[j])。
 *       
 *       // 我们可以简化：S_j 维护的是 {OR_value: end_of_range_start_index}。
 *       // 假设 S_j = { (v_1, r_1), (v_2, r_2), ..., (v_m, r_m) } 且 v_1 < v_2 < ... < v_m。
 *       // 且 r_1 > r_2 > ... > r_m = j。
 *       // 那么对于 i in [r_{k+1} + 1, r_k]，OR_sum(i, j) = v_k。 (定义 r_{m+1} = -1)
 * 
 *       // 遍历 S_j: (v_k, r_k)
 *       // 区间长度：length = r_k - (r_{k+1} + 1) + 1 = r_k - r_{k+1}
 *       // 对应的 OR_value 为 v_k。
 *       // 如果 v_k 在 {nums[i] | i in [r_{k+1} + 1, r_k]} 中出现过，那么这 length 个子数组都是好子数组。
 * 
 *       // 这是一个更复杂的计数问题，因为我们需要检查 v_k 是否是 [r_{k+1} + 1, r_k] 中任一元素的值。
 *       // 检查条件：v_k == nums[p] for some p in [r_{k+1} + 1, r_k]
 * 
 *       // 这是一个 O(N * log(MaxVal) * MaxVal) 的检查，太慢了。
 * 
 * 替代思路：固定 i，计算好子数组的数量 (O(N^2) 太慢)。
 * 
 * 回到 O(N * log(MaxVal)) 的 S_j 结构，这是唯一可行的方向。
 * 
 * 对于 S_j = { (v_1, r_1), ..., (v_m, r_m) } (按 r 降序排列，r_m = j)
 * 1. 区间 [r_{k+1} + 1, r_k] 对应的 OR_sum 是 v_k。
 * 2. 我们需要检查是否存在 p in [r_{k+1} + 1, r_k] 使得 nums[p] = v_k。
 * 
 * 如果 v_k == nums[p] 成立，那么这 `r_k - r_{k+1}` 个子数组都是好子数组。
 * 
 * 我们需要一个高效的方法来检查区间 [L, R] 是否包含值 V。
 * 
 * 由于 V 是 OR_sum，它本身就是所有元素 OR 的结果。
 * 如果 V = nums[p]，则 V 必然出现在区间内。
 * 
 * 优化检查：
 * 只需要检查 v_k 是否等于 nums[r_k] 或 nums[r_{k+1}+1] 等端点。
 * 不，如果 v_k = 10，区间是 [1, 100]，nums[50]=10，其他都是 1，则 v_k 匹配，但端点不匹配。
 * 
 * 结论：我们需要一个 Range Query Structure (例如 Segment Tree 或 Persistent Segment Tree) 来查询区间内是否存在特定值。
 * 由于值域太大 (10^9)，我们不能直接建树。
 * 
 * 考虑到 $N \le 10^5$ 且 $\text{distinct OR values} \le 30$，我们只需要对这 30 个值进行查询。
 * 
 * 对于每个值 V，我们预处理所有出现 V 的位置的列表 `positions[V]`。
 * 当检查区间 $[L, R]$ 是否包含 $V$ 时，我们在 `positions[V]` 中二分查找是否存在 $\le R$ 且 $\ge L$ 的位置。
 * 
 * 最终算法步骤 (O(N * log(MaxVal) * log N)):
 * 1. 预处理：建立 `map<int64, vector<int>> positions` 存储每个值出现的位置。
 * 2. 初始化 `total_count = 0`, `current_ors = []` (stores {val, start_index}).
 * 3. for j = 0 to N-1:
 *    a. `next_ors = []`
 *    b. Add {nums[j], j} to `next_ors`.
 *    c. For each {val, start_i} in `current_ors`:
 *       new_val = val | nums[j]
 *       Add {new_val, start_i} to `next_ors`.
 *    d. Sort `next_ors` by value, then by index (to ensure unique representation for the next step). Use a map to merge duplicates: `S_j = {val: leftmost_start_index}`.
 *    e. Convert $S_j$ map entries into a list $L_j = \{(v_1, r_1), ..., (v_m, r_m)\}$ sorted by $r_k$ descending ($r_m = j$). $r_{m+1} = -1$.
 *    f. For k = 1 to m:
 *       i. $v = v_k$, $r_k = r_k$.
 *       ii. $L = r_{k+1} + 1$.
 *       iii. Segment length: $len = r_k - L + 1$.
 *       iv. Check: Does `positions[v]` contain any index $p$ such that $L \le p \le r_k$? (Using binary search/std::lower_bound on `positions[v]`).
 *       v. If true, `total_count += len`.
 *    g. `current_ors = L_j`.
 * 4. Return `total_count`.
 * 
 * 考虑到题目要求是返回 `Int64`，所有计数都用 `int64`。
 */

typedef long long int64;

int64 solve(vector<int64> nums) {
    int n = nums.size();
    int64 total_count = 0;

    // 1. Preprocessing: Store positions for fast existence check
    vector<vector<int>> positions(1000000001, vector<int>()); // Max value is 10^9, this is too large for array indexing.
    // Since we only care about values present in nums, use a map.
    map<int64, vector<int>> value_positions;
    for (int i = 0; i < n; ++i) {
        value_positions[nums[i]].push_back(i);
    }

    // current_ors stores {OR_value, leftmost_start_index} for subsegments ending at j-1.
    // We use a map to automatically handle merging identical OR values, keeping the minimum start index.
    // Map: OR_value -> leftmost_start_index
    map<int64, int> current_ors_map;

    for (int j = 0; j < n; ++j) {
        // 2. Calculate next_ors_map (for segments ending at j)
        map<int64, int> next_ors_map;

        // Case 1: Segment [j..j]
        int64 val_j = nums[j];
        next_ors_map[val_j] = j;

        // Case 2: Extend segments ending at j-1
        for (const auto& pair : current_ors_map) {
            int64 prev_val = pair.first;
            int start_i = pair.second;

            int64 new_val = prev_val | val_j;

            // Merge: if new_val already exists, keep the minimum start index
            if (next_ors_map.find(new_val) == next_ors_map.end() || start_i < next_ors_map[new_val]) {
                next_ors_map[new_val] = start_i;
            }
        }

        // 3. Convert map to sorted list L_j for range processing
        // L_j: vector of {OR_value, start_index} sorted by start_index ascending.
        vector<pair<int64, int>> L_j;
        for (const auto& pair : next_ors_map) {
            // pair.first is OR_value, pair.second is leftmost_start_index
            L_j.push_back({pair.first, pair.second});
        }

        // Sort by start_index ascending (r_k)
        sort(L_j.begin(), L_j.end(), [](const pair<int64, int>& a, const pair<int64, int>& b) {
            return a.second < b.second;
        });

        // 4. Range summation and counting
        // L_j = {(v_1, r_1), ..., (v_m, r_m)} where r_1 < r_2 < ... < r_m = j
        int m = L_j.size();

        // Use r_{m+1} = -1 for the last segment
        int r_next = -1; 

        // Iterate backwards from k=m down to 1
        for (int k = m - 1; k >= 0; --k) {
            int64 v_k = L_j[k].first;
            int r_k = L_j[k].second;

            // The range of starting indices i where OR_sum(i, j) = v_k is [r_{k+1} + 1, r_k].
            // Since L_j is sorted by r ascending, we iterate backwards, so r_{k+1} is the next index in the backward iteration.
            // If k < m-1, r_{k+1} is L_j[k+1].second. If k = m-1, r_{k+1} is the conceptual -1.

            // In our backward iteration (k=m-1 down to 0):
            // r_k = L_j[k].second
            // r_{k+1} = r_next (which holds the start index of the segment immediately to the right of the current one)

            int L = r_next + 1; // Start of the current range
            int R = r_k;       // End of the current range

            // Segment length: R - L + 1
            int64 segment_len = R - L + 1;

            // Check: Does value v_k exist in the range [L, R]?
            if (value_positions.count(v_k)) {
                const auto& positions_v = value_positions.at(v_k);

                // Find the first position >= L
                auto it = lower_bound(positions_v.begin(), positions_v.end(), L);

                // If such a position exists AND it is <= R, then the condition is met.
                if (it != positions_v.end() && *it <= R) {
                    total_count += segment_len;
                }
            }

            // Update r_next for the next iteration (k-1)
            r_next = r_k;
        }

        // Update for the next outer iteration (j -> j+1)
        current_ors_map = next_ors_map;
    }

    return total_count;
}
