    if (start > end) return false;

    Int64 or_sum = 0;
    for (int i = start; i <= end; ++i) {
        or_sum |= nums[i];
    }

    // 检查 or_sum 是否存在于子数组中
    for (int i = start; i <= end; ++i) {
        if (nums[i] == or_sum) {
